# Category: business_logic_flaw

def validate_cart_items(cart_items):
    for item in cart_items:
        if item['quantity'] <= 0 or item['price'] < 0:
            return False, "Invalid cart items"
    return True, cart_items

def apply_discount_codes(cart_items, discount_code, user):
    discounts = {'SAVE10': 0.1, 'ADMIN50': 0.5}
    admin_only_codes = ['ADMIN50']
    user_tier_codes = {'GOLD': ['SAVE10']}
    
    if discount_code in admin_only_codes and not user['is_admin']:
        return False, "Unauthorized discount code"
    if discount_code in user_tier_codes.get(user['tier'], []):
        discount = discounts.get(discount_code, 0)
    else:
        discount = 0
    
    for item in cart_items:
        item['price'] -= item['price'] * discount
    return True, cart_items

def calculate_tax(cart_items, tax_rate):
    total_tax = 0
    for item in cart_items:
        total_tax += item['price'] * item['quantity'] * tax_rate
    return total_tax

def process_payment(cart_items, total_tax, payment_info):
    total_amount = sum(item['price'] * item['quantity'] for item in cart_items) + total_tax
    if payment_info['balance'] >= total_amount:
        payment_info['balance'] -= total_amount
        return True, total_amount
    return False, "Insufficient funds"

def create_order_record(cart_items, total_amount, user):
    order_record = {
        'user_id': user['id'],
        'items': cart_items,
        'total_amount': total_amount,
        'status': 'completed'
    }
    return order_record

def checkout_process(cart_items, discount_code, user, tax_rate, payment_info):
    valid, result = validate_cart_items(cart_items)
    if not valid:
        return result
    
    valid, result = apply_discount_codes(result, discount_code, user)
    if not valid:
        return result
    
    total_tax = calculate_tax(result, tax_rate)
    
    valid, result = process_payment(result, total_tax, payment_info)
    if not valid:
        return result
    
    order_record = create_order_record(cart_items, result, user)
    return order_record

# Example usage
cart_items = [{'name': 'item1', 'quantity': 2, 'price': 100}]
user = {'id': 1, 'is_admin': False, 'tier': 'GOLD'}
